create table tb_categoria (id bigint generated by default as identity, nome varchar(255), primary key (id));
create table tb_comanda (id bigint generated by default as identity, primary key (id));
create table tb_funcionario (data_nascimento timestamp(6), id bigint generated by default as identity, cargo varchar(255), cpf varchar(255), email varchar(255), nome varchar(255), senha varchar(255), primary key (id));
create table tb_item (preco numeric(38,2), quantidade integer, categoria_id bigint, id bigint generated by default as identity, descricao varchar(255), nome varchar(255), primary key (id));
create table tb_mesa (numero integer, id bigint generated by default as identity, cliente varchar(255), observacoes varchar(255), primary key (id));
create table tb_pedido (forma_pagamento tinyint check (forma_pagamento between 0 and 3), status_pedido tinyint check (status_pedido between 0 and 2), comanda_id bigint, data timestamp(6) with time zone, funcionario_id bigint, id bigint generated by default as identity, mesa_id bigint, primary key (id));
create table tb_permissao (id bigint generated by default as identity, descricao varchar(255), nome varchar(255), primary key (id));
create table tb_permissao_funcionario (funcionario_id bigint not null, permissao_id bigint not null);
alter table if exists tb_item add constraint fk_item_categoria foreign key (categoria_id) references tb_categoria;
alter table if exists tb_pedido add constraint fk_pedido_comanda foreign key (comanda_id) references tb_comanda;
alter table if exists tb_pedido add constraint fk_pedido_funcionario foreign key (funcionario_id) references tb_funcionario;
alter table if exists tb_pedido add constraint fk_pedido_mesa foreign key (mesa_id) references tb_mesa;
alter table if exists tb_permissao_funcionario add constraint fk_permisaofuncionario_funcionario foreign key (funcionario_id) references tb_funcionario;
alter table if exists tb_permissao_funcionario add constraint fk_permissaofuncionario_permissao foreign key (permissao_id) references tb_permissao;
